-- Create zip_code_economics table for neighborhood income comparison
CREATE TABLE public.zip_code_economics (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    zip_code text NOT NULL UNIQUE,
    median_household_income integer NOT NULL,
    created_at timestamp with time zone NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.zip_code_economics ENABLE ROW LEVEL SECURITY;

-- Allow authenticated users to read
CREATE POLICY "Authenticated users can view zip economics"
ON public.zip_code_economics
FOR SELECT
USING (true);

-- Super admins can manage
CREATE POLICY "Super admins can manage zip economics"
ON public.zip_code_economics
FOR ALL
USING (has_role(auth.uid(), 'super_admin'));

